INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Visual workflow builder$q$, $q$Design multi-step, multi-channel notification workflows with trigger conditions, delays, digesting and fallback logic through a drag-and-drop editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Single trigger API$q$, $q$Fire one API call from application code and let Novu resolve the right channels, providers and content per subscriber.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Embeddable Inbox$q$, $q$Drop a pre-built in-app notification center into React, Angular or Vue apps, or build a custom one against the headless API.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$55-plus provider integrations$q$, $q$Connect existing email, SMS, push and chat providers such as SendGrid, Twilio, Firebase and Slack without rewriting delivery logic.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Digest and batching$q$, $q$Aggregate multiple events into a single digest notification to avoid overwhelming end users.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Subscriber preferences$q$, $q$Let end users opt in or out of specific notification types and channels through a preference center.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Multi-environment support$q$, $q$Separate development, staging and production workflows so testing never touches live subscribers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Self-hosting option$q$, $q$Run the fully open-source engine on your own infrastructure to avoid per-run cloud pricing and keep full data control.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Open-source core means no vendor lock-in and the option to self-host for free$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Single API replaces integrations with multiple separate notification providers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Generous free tier (10,000 workflow runs/month) suitable for small projects$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Visual workflow editor speeds up building and iterating on notification logic without redeploys$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Embeddable Inbox component saves significant frontend engineering time for in-app notifications$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Usage-based workflow-run pricing can escalate quickly for high-volume applications$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Team and Enterprise plans are priced well above typical small-team notification budgets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Self-hosting requires ongoing infrastructure maintenance that the cloud plan is meant to remove$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Advanced features like SSO, SCIM and HIPAA support are locked behind custom Enterprise pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$As a relatively young company (founded 2021), long-term roadmap stability is less proven than legacy messaging vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$What is Novu used for?$q$, $q$Novu is used by developers to build and manage multi-channel notification systems, sending email, SMS, push, chat and in-app notifications through one API and one workflow engine instead of separate provider integrations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Is Novu free to use?$q$, $q$Yes. Novu's open-source engine can be self-hosted for free, and the hosted Novu Cloud has a free tier that includes 10,000 workflow runs per month, all channels, and up to 3 team members.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Can Novu be self-hosted?$q$, $q$Yes, Novu's core notification engine is open source and can be deployed on your own infrastructure, which avoids per-workflow-run cloud pricing entirely.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$How does Novu's pricing work?$q$, $q$Novu Cloud charges based on monthly workflow runs, where one run equals one trigger event that can fan out across multiple channels. Plans range from a free tier to Pro ($30/month), Team ($250/month) and custom Enterprise pricing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$What channels does Novu support?$q$, $q$Novu supports email, SMS, push notifications, in-app inbox notifications and chat channels like Slack and Discord, through more than 55 built-in provider integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Who is Novu built for?$q$, $q$Novu is built for engineering and product teams that need reliable, centralized notification infrastructure, from early-stage startups to mid-market SaaS companies replacing custom-built notification systems.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$What are the main alternatives to Novu?$q$, $q$Common alternatives include Courier, Knock and Suprsend, as well as building notification logic directly on top of individual provider APIs such as Twilio or SendGrid.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Product notification centers$q$, $q$Add an in-app notification inbox to a SaaS product using Novu's embeddable Inbox component instead of building one from scratch.$q$, $q$Product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Transactional and lifecycle messaging$q$, $q$Trigger onboarding emails, password resets, billing alerts and usage digests across channels from unified workflows.$q$, $q$SaaS and B2B software companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Replacing fragmented provider integrations$q$, $q$Consolidate separate SendGrid, Twilio and push-notification integrations into a single API and workflow layer to reduce maintenance overhead.$q$, $q$Platform and infrastructure engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["10,000 workflow runs/month","All notification channels","Up to 20 workflows","2 environments","24-hour activity feed retention","Up to 3 team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Pro$q$, $q$$30/month$q$, $q$monthly$q$, NULL, $q$["30,000+ workflow runs/month","7-day activity feed retention","No Novu branding","Advanced email editor","Higher rate limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Team$q$, $q$$250/month$q$, $q$monthly$q$, NULL, $q$["250,000+ workflow runs/month","Up to 10 environments","90-day activity retention","Unlimited team members","Role-based access control"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["10M+ workflow runs/month","Custom retention","HIPAA BAA","SSO and SCIM","Private support","Self-hosting option"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Novu is an open-source notification infrastructure platform built for developers who need to send email, SMS, push, chat and in-app notifications without wiring together separate provider SDKs. Instead of hard-coding logic for Twilio, SendGrid, Firebase Cloud Messaging and Slack directly into an application, teams define reusable workflows in Novu and trigger them with a single API call.$q$, $q$Founded in 2021 in Tel Aviv and originally launched under the name Notifire, Novu grew out of its founders' repeated frustration with rebuilding notification systems at previous jobs. The company raised a $6.6 million seed round and has since built both an open-source engine that any team can self-host and a managed cloud offering (Novu Cloud) for teams that would rather not run the infrastructure themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Novu is a visual workflow editor where developers configure trigger conditions, channel ordering and fallback logic, digest and batching windows, delay steps, and per-subscriber preferences, all version-controlled and testable across environments.$q$, $q$Novu also ships an embeddable Inbox component with SDKs for React, Angular and Vue (plus a headless API for any framework), giving product teams a ready-made in-app notification center. It supports more than 55 provider integrations spanning email, SMS, push and chat channels, along with subscriber preference centers, translation and localization support, and multi-environment workspaces so staging and production workflows stay isolated.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('555aaf18-6846-4042-ba95-cc4fd3189aec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Novu prices its hosted cloud plans by monthly workflow runs, where one run corresponds to a single trigger event that can still deliver across several channels. The Free plan covers 10,000 runs per month with up to 20 workflows and 3 team members, making it usable for small projects and early-stage products.$q$, $q$Paid tiers scale from Pro at $30/month (30,000-plus runs, no Novu branding, longer activity retention) to Team at $250/month (250,000-plus runs, unlimited members, role-based access control) up to a custom-priced Enterprise plan with HIPAA support, SSO, SCIM and self-hosting for teams that need to run Novu on their own infrastructure at no per-run cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Task and project management$q$, $q$Organize work in list, Kanban board, Gantt chart and calendar views across unlimited projects on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Time tracking and timesheets$q$, $q$Log billable and non-billable hours against tasks and projects for client billing and internal reporting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Meeting management$q$, $q$Schedule meetings, share agendas, and record and distribute meeting minutes directly within projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Issue and risk management$q$, $q$Track project risks and issues with a built-in risk register, useful for teams that need lightweight governance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Kanban boards$q$, $q$Visualize workflow stages and move tasks across custom board columns for agile-style task tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Custom roles and permissions$q$, $q$Define granular access controls and custom statuses on Business and Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Team collaboration$q$, $q$Comment on tasks, attach files, and get status updates in a shared workspace.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Low per-user pricing makes it accessible for small teams and startups$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Combines task management, time tracking and risk management in one tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Free plan is usable indefinitely for very small teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Multiple work views (list, Kanban, Gantt, calendar) suit different team preferences$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Native issue and risk tracking is uncommon at this price point$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Interface and feature depth lag behind larger competitors like Asana or Monday.com$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Free plan is capped at 5 team members and limited storage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Risk management features are only available on Business plan and above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Smaller company size means a narrower support and integration ecosystem than venture-backed rivals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Some advanced customization requires contacting sales on the Enterprise tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$What is nTask used for?$q$, $q$nTask is used for project and task management, including planning, Kanban boards, time tracking, meeting management, and issue and risk tracking for small to mid-sized teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Is nTask free?$q$, $q$Yes, nTask offers a free plan for up to 5 team members with 5 workspaces and 200 MB of storage, usable indefinitely without payment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$How much does nTask cost?$q$, $q$Paid plans start at $3 per user per month (billed annually) for Premium, and $8 per user per month (billed annually) for Business, which adds risk management and advanced permissions. Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Does nTask include time tracking?$q$, $q$Yes, nTask has built-in time tracking and timesheets that can be logged against tasks and projects for reporting and billing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Does nTask support risk management?$q$, $q$Yes, nTask includes a native risk and issue management module on its Business and Enterprise plans, which is uncommon among similarly priced project management tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Who founded nTask and when?$q$, $q$nTask was founded in 2015 by Fawad Ansari and is headquartered in Frisco, Texas.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$What are alternatives to nTask?$q$, $q$Common alternatives include Asana, Trello, Monday.com, ClickUp and Wrike, though nTask is typically positioned as a lower-cost option for smaller teams.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Small team project tracking$q$, $q$Manage tasks, deadlines and deliverables across multiple client or internal projects in one workspace.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Agency and consulting time billing$q$, $q$Track billable hours against client projects using built-in time tracking and timesheets.$q$, $q$Agencies and consulting firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Lightweight project risk tracking$q$, $q$Maintain a basic risk and issue register alongside day-to-day task management without adopting separate PMO software.$q$, $q$IT services and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Free$q$, $q$$0$q$, $q$forever free$q$, NULL, $q$["Up to 5 team members","5 workspaces","200 MB storage","Unlimited tasks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Premium$q$, $q$$3/user/month$q$, $q$billed annually$q$, NULL, $q$["Unlimited projects","Unlimited Kanban boards","Pay-as-you-grow user pricing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Business$q$, $q$$8/user/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Premium","Risk management","Custom statuses","Custom roles and permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Enterprise-grade security","Custom configuration","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$nTask is an all-in-one project management platform founded in 2015 and headquartered in Frisco, Texas. It was built to give small and mid-sized teams a single workspace for tasks, projects, meetings, time tracking and basic risk management, without requiring separate tools for each function.$q$, $q$The platform is used by an estimated 200,000-plus organizations for managing campaigns, sprints, product development and client work, and is frequently positioned as a lower-cost, simpler alternative to larger enterprise project management suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$nTask combines task management with list, Kanban board, Gantt chart and calendar views, letting teams choose how they visualize work. It also includes built-in time tracking and timesheets, meeting management with agendas and shareable minutes, and file and document collaboration.$q$, $q$A standout feature relative to many task-management competitors is native issue and risk management, giving teams a lightweight risk register and issue log without needing a separate governance tool. Custom statuses, roles and permissions are available on higher-tier plans for teams that need more structured workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('336862e5-da77-44d8-bed2-981fb6c31cb8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$nTask uses a freemium, per-user pricing model. The Free plan allows up to 5 team members, 5 workspaces and 200 MB of storage indefinitely at no cost, making it accessible for very small teams.$q$, $q$Paid plans scale by user count: Premium starts at $3 per user per month (billed annually) with unlimited projects and boards, and Business is $8 per user per month (billed annually) adding risk management, custom roles and advanced permissions. An Enterprise tier with custom security and configuration is available by contacting nTask sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Simple PUT/POST publishing$q$, $q$Send a notification with a single HTTP request from curl, scripts, CI pipelines or any language with an HTTP client.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$On-the-fly topics$q$, $q$Create pub-sub channels instantly by publishing or subscribing to any topic name, with no pre-registration required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Cross-platform apps$q$, $q$Receive notifications on iOS, Android, desktop browsers and via the command line.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Self-hosting$q$, $q$Run your own ntfy server for full control over data, topics and retention at zero licensing cost.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Rich notification options$q$, $q$Attach files up to plan limits, set priority levels, add action buttons, tags and emoji shortcuts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Broad automation integrations$q$, $q$Works out of the box with GitHub Actions, Home Assistant, Uptime Kuma, Sonarr, Radarr and other DevOps and home-lab tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Reserved private topics$q$, $q$Paid hosted plans allow reserving topics that are not guessable or shared, unlike the semi-private default topics.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Fully open source and free to self-host with no feature restrictions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Extremely simple API, sending a notification requires only one HTTP request$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$No account or app registration needed to start using the public server$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Strong integration support across DevOps, monitoring and home-automation tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Active open-source community with frequent releases and transparent development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Default public-server topics are only semi-private, not fully secure by design$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Self-hosting requires basic server administration knowledge$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Paid hosted tiers are needed for reserved private topics and higher throughput$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Lacks the polished enterprise features and SLAs of commercial alerting platforms like PagerDuty$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Attachment size and message-rate limits on the free public server can be restrictive for heavy use$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$What is ntfy used for?$q$, $q$ntfy is used to send push notifications to phones, desktops or scripts via simple HTTP requests, commonly for CI/CD alerts, server monitoring, home-automation triggers and personal reminders.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Is ntfy free?$q$, $q$Yes, ntfy is free and open source. You can self-host your own server at no cost or use the public ntfy.sh server without an account.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Can I self-host ntfy?$q$, $q$Yes, ntfy's server is fully open source under Apache 2.0 and GPLv2 and is designed to be self-hosted on your own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$How much do ntfy's paid plans cost?$q$, $q$Hosted plans on ntfy.sh start around $5-6/month for Supporter, scaling to around $10-12/month for Pro and $20-25/month for Business, offering higher limits and reserved private topics.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Who created ntfy?$q$, $q$ntfy was created by developer Philipp Heckel, known on GitHub as binwiederhier, and has since grown into a community-driven open-source project.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Is ntfy secure and private?$q$, $q$By default, public server topics act like a shared password and are only semi-private. For stronger privacy, users can self-host or subscribe to a paid plan with reserved, non-guessable topics.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$What are alternatives to ntfy?$q$, $q$Alternatives include Pushover, Pushbullet, Gotify and OneSignal, though ntfy is distinguished by being fully open source and self-hostable at no cost.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$CI/CD and server monitoring alerts$q$, $q$Trigger push notifications from build pipelines, cron jobs or uptime monitors when a job fails or a server goes down.$q$, $q$Developers and DevOps engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Home lab and home automation notifications$q$, $q$Send alerts from Home Assistant, Sonarr, Radarr or other self-hosted services directly to a phone.$q$, $q$Self-hosters and homelab enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Lightweight personal or team alerting$q$, $q$Replace a heavyweight paid notification service with a simple, scriptable HTTP-based alerting system.$q$, $q$Individuals and small technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Self-hosted / Public server$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full open-source server","Unlimited self-hosted topics","Public ntfy.sh server, no signup required","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Supporter$q$, $q$~$5-6/month$q$, $q$monthly or annual$q$, NULL, $q$["2,500 daily messages","3 reserved private topics","Up to 25 MB attachments"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Pro$q$, $q$~$10-12/month$q$, $q$monthly or annual$q$, NULL, $q$["20,000 daily messages","10 reserved private topics","Up to 250 MB attachments"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$Business$q$, $q$~$20-25/month$q$, $q$monthly or annual$q$, NULL, $q$["50,000 daily messages","50 reserved private topics","Up to 1 GB attachments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ntfy is an open-source, HTTP-based pub-sub notification service created by developer Philipp Heckel that grew from a personal project into a widely used tool in the self-hosting and developer communities. It lets anyone send a push notification to a phone, desktop or terminal with a simple PUT or POST request, without needing an account, API key or app registration.$q$, $q$Because ntfy is fully open source under Apache 2.0 and GPLv2, it can be self-hosted for complete control and zero cost, or used via the free public server at ntfy.sh. The project has attracted a large open-source community, with more than 30,000 GitHub stars and 300-plus contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Topics in ntfy are created on the fly simply by publishing or subscribing to a topic name, and messages support rich formatting including priorities, action buttons, tags, emoji shortcuts and file attachments. Native apps are available for iOS, Android and desktop, alongside a web app and simple curl-based publishing.$q$, $q$ntfy integrates with a wide range of DevOps and self-hosted tools, including GitHub Actions, Home Assistant, Uptime Kuma, Sonarr and Radarr, making it a popular choice for build alerts, monitoring notifications and home-automation triggers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ntfy is free to use in two ways: self-hosting the open-source server on your own infrastructure at no cost, or using the public ntfy.sh server without signing up (topics act as a shared secret and are only semi-private).$q$, $q$For users who want private reserved topics, higher message limits and larger attachments without running their own server, ntfy.sh offers paid hosted tiers: Supporter (around $5-6/month), Pro (around $10-12/month) and Business (around $20-25/month), with larger custom deployments available on request.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65e976a6-18cc-449b-b109-b26bbd870c7c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Template-based scanning engine$q$, $q$Detect vulnerabilities using a YAML DSL where each check is a shareable, version-controlled template rather than hardcoded logic.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Massive community template library$q$, $q$Access thousands of officially maintained and community-contributed templates covering CVEs, misconfigurations and exposures.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Fast, concurrent scanning$q$, $q$Written in Go for high-throughput scanning across large target lists with configurable rate limiting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Multi-protocol coverage$q$, $q$Scan web applications, APIs, DNS records, network services and cloud configurations from a single tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$CI/CD and automation integration$q$, $q$Run Nuclei as part of build pipelines and security automation workflows for continuous vulnerability detection.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Rapid CVE coverage$q$, $q$New templates for high-profile disclosed vulnerabilities are frequently published within hours of public disclosure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Custom template authoring$q$, $q$Write organization-specific templates to detect proprietary application logic flaws or internal misconfigurations.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Completely free and open source with no feature restrictions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Extremely fast, low-overhead scanning suitable for large-scale and CI/CD use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Massive, continuously updated community template library covers new CVEs quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Declarative YAML templates are easy to read, write and audit compared to compiled scanner logic$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Backed by an active, well-funded company (ProjectDiscovery) ensuring ongoing development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Effectiveness depends heavily on template coverage and quality, gaps can mean missed vulnerabilities$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Command-line-first tool has a steeper learning curve than GUI-based commercial scanners$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$No built-in reporting, dashboards or team collaboration, those require the separate paid Cloud Platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$False positives can occur with community-submitted templates that are not officially vetted$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Requires ongoing template updates and tuning to stay effective against new threats$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$What is Nuclei used for?$q$, $q$Nuclei is used to scan web applications, APIs, networks, DNS and cloud configurations for known vulnerabilities, misconfigurations and exposures using community-maintained YAML templates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Is Nuclei free?$q$, $q$Yes, Nuclei is completely free and open source with no paywalled features. ProjectDiscovery separately sells a hosted Cloud Platform built on top of it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Who makes Nuclei?$q$, $q$Nuclei is developed by ProjectDiscovery, a cybersecurity company founded in 2019 and headquartered in San Francisco, which has raised roughly $25 million in funding including a Series A led by CRV.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$How does Nuclei detect vulnerabilities?$q$, $q$Nuclei runs configurable templates written in a YAML-based domain-specific language against a target, each template encoding a specific vulnerability check, misconfiguration signature or exposure pattern.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Is Nuclei suitable for CI/CD pipelines?$q$, $q$Yes, Nuclei is commonly integrated into CI/CD pipelines and automated security workflows to continuously scan for newly disclosed vulnerabilities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Who typically uses Nuclei?$q$, $q$Penetration testers, bug bounty hunters, red teams and DevSecOps engineers use Nuclei for fast, automatable vulnerability scanning.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$What are alternatives to Nuclei?$q$, $q$Alternatives include Nmap with NSE scripts, OpenVAS, Burp Suite and Nessus, though Nuclei is distinguished by its lightweight YAML template model and open-source, community-driven update cadence.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Continuous vulnerability scanning in CI/CD$q$, $q$Run Nuclei automatically on every deployment or on a schedule to catch newly introduced or newly disclosed vulnerabilities early.$q$, $q$DevSecOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Penetration testing and bug bounty reconnaissance$q$, $q$Quickly identify known vulnerabilities and misconfigurations across large sets of targets during engagements.$q$, $q$Penetration testers and bug bounty hunters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Attack surface monitoring$q$, $q$Continuously scan external-facing assets for exposures and CVEs as part of an ongoing security posture program.$q$, $q$Security teams at growing companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$Nuclei (open source)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full scanning engine","Access to community template library","Unlimited self-hosted scans","CI/CD integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$ProjectDiscovery Cloud Platform$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Hosted scanning infrastructure","Continuous attack surface management","Team collaboration and reporting","Priority template updates"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nuclei is an open-source vulnerability scanner developed by ProjectDiscovery, a San Francisco-based cybersecurity company founded in 2019. Unlike traditional scanners with hardcoded detection logic, Nuclei runs configurable, community-authored templates written in a simple YAML-based domain-specific language, letting the security community add and update checks continuously.$q$, $q$The project has become one of the most widely used open-source scanners in security testing, processing over 50 million scans a month across more than 100 countries, and is frequently used in penetration testing, bug bounty hunting and continuous attack-surface monitoring.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nuclei's core strength is its template-based architecture: each vulnerability check, misconfiguration or exposure signature is defined declaratively in YAML rather than compiled into the tool itself, so new checks for freshly disclosed CVEs can ship within hours through the public template repository.$q$, $q$Built in Go for speed, Nuclei supports high-concurrency scanning across large target lists and covers web applications, APIs, DNS, network services and cloud misconfigurations. It is designed to be scripted into CI/CD pipelines and automation workflows rather than run only as a manual, interactive tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nuclei itself is completely free and open source, with no paywalled features or usage limits when self-hosted and run from the command line or CI pipeline.$q$, $q$ProjectDiscovery monetizes separately through the ProjectDiscovery Cloud Platform, a hosted product built on top of Nuclei that adds continuous attack-surface management, team collaboration and reporting; pricing for that platform is custom and quoted directly by ProjectDiscovery's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Real-time collaborative editing$q$, $q$Multiple team members can edit the same document simultaneously with live multiplayer cursors, similar to Google Docs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Graph view$q$, $q$Visualize how wiki items link to one another in an interactive graph, making it easy to discover related documentation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Multiple content views$q$, $q$Switch between list, Kanban-style board and grid views to organize the same underlying content differently.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Instant search and fast performance$q$, $q$Nuclino is built for near-instant load times and search results even in large knowledge bases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Rich content embedding$q$, $q$Embed files, images, code blocks, diagrams and content from tools like Figma and Google Drive directly into pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Nested, interlinked items$q$, $q$Structure documentation hierarchically while cross-linking related items to build a true wiki-style knowledge graph.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Advanced permissions and audit logs$q$, $q$Business and Enterprise plans add granular access controls and activity auditing for larger teams.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Noticeably faster and simpler than heavier tools like Notion or Confluence$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Free plan is generous enough for small teams to fully evaluate before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Unique graph view makes it easy to see how documentation is interconnected$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Bootstrapped, profitable company with a stable, long-running product (founded 2015)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Real-time multiplayer editing works smoothly even with several simultaneous editors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Fewer advanced features (databases, automations, integrations) compared to Notion or Coda$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Free plan's 50-item cap is restrictive for growing teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$AI features and audit logs are locked behind the Business tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Smaller company size than VC-backed competitors means a slower pace of major feature releases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Less extensive third-party integration ecosystem than larger knowledge-base platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$What is Nuclino used for?$q$, $q$Nuclino is used as a team wiki and knowledge base for documenting processes, meeting notes, product specs and onboarding material in a fast, real-time collaborative workspace.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Is Nuclino free?$q$, $q$Yes, Nuclino offers a free plan for up to 50 items and 2 GB of storage, suitable for individuals or small teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$How much does Nuclino cost?$q$, $q$Paid plans start at roughly $6 per user per month billed annually for the Starter plan, with the Business plan around $10 per user per month; Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Is Nuclino a Notion alternative?$q$, $q$Yes, Nuclino is commonly used as a faster, simpler alternative to Notion for teams that primarily need a wiki and knowledge base rather than databases and complex automations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Who founded Nuclino?$q$, $q$Nuclino was founded in 2015 near Munich, Germany by Bjorn Michelsen, Jonathan Kienzle and Veronika Fischer, and has remained self-funded and profitable ever since.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Does Nuclino support real-time collaboration?$q$, $q$Yes, Nuclino supports real-time multiplayer editing where multiple team members can edit the same document simultaneously.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$What are alternatives to Nuclino?$q$, $q$Common alternatives include Notion, Confluence, Slite, Coda and Guru, with Nuclino distinguished by its speed, minimalism and graph view of linked content.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Internal team wiki$q$, $q$Centralize company processes, onboarding guides and policies in a searchable, always-up-to-date wiki.$q$, $q$Startups and remote-first teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Product and engineering documentation$q$, $q$Document product specs, architecture decisions and meeting notes in interlinked pages that are easy to navigate.$q$, $q$Product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Lightweight project knowledge base$q$, $q$Track project-related notes and decisions on Kanban-style boards alongside standard wiki pages.$q$, $q$Agencies and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Up to 50 items","2 GB total storage","Unlimited collaborators","Basic workspace features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Starter$q$, $q$$6/user/month$q$, $q$billed annually (or $8/user/month billed monthly)$q$, NULL, $q$["Unlimited items and boards","Advanced integrations","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Business$q$, $q$$10/user/month$q$, $q$billed annually$q$, NULL, $q$["AI-powered tools","Advanced permissions","Audit logs","Enterprise-grade security"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Custom deployment options","Dedicated support","Advanced compliance features"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nuclino is a real-time team wiki and knowledge base founded in 2015 near Munich, Germany, and now based in Grunwald. Unlike most of its venture-backed competitors, Nuclino has remained fully bootstrapped and profitable since founding, growing to more than $3 million in annual recurring revenue and over 12,000 customers with a small team of around 20 people.$q$, $q$The product is built around the idea of being 'your team's collective brain,' emphasizing instant load times and a minimal interface over the sprawling feature sets found in tools like Notion or Confluence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Teams organize content into workspaces made up of interlinked items, which can be viewed as a list, Kanban-style board, grid, or a unique graph view that visually maps how documents connect to one another. Editing is real time and multiplayer, similar to Google Docs, with rich text, embedded files, code blocks and diagram support.$q$, $q$Nuclino integrates with tools such as Slack, Figma and Google Drive to embed external content directly into wiki pages, and higher-tier plans add AI-assisted writing tools, advanced permissions and audit logs for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('31891521-7412-481e-8809-b74fa059bcf3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nuclino's Free plan covers up to 50 items and 2 GB of storage, enough for individuals or very small teams to fully evaluate the product before paying.$q$, $q$Paid plans are per-user: Starter runs about $6/user/month billed annually (around $8/month billed monthly) with unlimited items and boards, Business runs about $10/user/month and adds AI features, advanced permissions and audit logs, and Enterprise is custom-priced for larger deployments.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Configure-price-quote (CPQ)$q$, $q$Build complex, multi-product quotes with guided selling and approval workflows for sales reps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Price Builder$q$, $q$Design, test and deploy new pricing models and promotions quickly without engineering involvement.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Usage-based and hybrid billing$q$, $q$Support subscription, usage-based and hybrid billing models natively for modern SaaS pricing strategies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Order and contract management$q$, $q$Manage orders, amendments and renewals with integrated e-signature and contract lifecycle tool support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Revenue intelligence dashboards$q$, $q$Get real-time visibility into ARR, renewals and expansion revenue without manual cross-system reconciliation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Native Salesforce integration$q$, $q$Built natively on Salesforce so quoting and billing data stay in sync with existing CRM workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Rapid implementation programs$q$, $q$Quick Start onboarding aims to move customers from kickoff to live production in as little as four to six weeks.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Unifies CPQ, billing and revenue intelligence in one platform instead of multiple point solutions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Purpose-built for complex, modern SaaS pricing models including usage-based and hybrid pricing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Native Salesforce integration keeps sales and revenue data synchronized$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Well-funded ($35M raised) with an experienced RevOps-focused team backing continued development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Fast implementation track can bring customers live in weeks rather than months$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$No public pricing, requires a sales conversation before understanding cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Primarily built for Salesforce-centric organizations, less suited to non-Salesforce CRM stacks$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Younger, smaller company than incumbents like Zuora or Salesforce CPQ, so ecosystem and track record are less established$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Best suited to mid-market and enterprise companies, likely overkill for very small SaaS businesses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Migrating from legacy CPQ or billing systems can require a significant implementation effort$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$What is Nue used for?$q$, $q$Nue is used by B2B SaaS companies to manage configure-price-quote (CPQ), subscription and usage-based billing, order management and revenue intelligence in one unified platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$How much does Nue cost?$q$, $q$Nue does not publish public pricing. Cost is quoted individually based on a company's revenue model, deal volume and implementation needs after a sales demo.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Is Nue built on Salesforce?$q$, $q$Yes, Nue is built natively on the Salesforce platform, allowing quoting, billing and revenue data to stay synchronized with existing CRM workflows.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Who founded Nue and when?$q$, $q$Nue was founded in 2019, originally under the name Ruby.io, and is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Does Nue support usage-based pricing?$q$, $q$Yes, Nue natively supports usage-based, subscription and hybrid billing models designed for modern SaaS pricing strategies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$How much funding has Nue raised?$q$, $q$Nue has raised approximately $35 million in total funding, including a $20 million Series A round led by Inovia Capital in 2025.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$What are alternatives to Nue?$q$, $q$Common alternatives include Salesforce CPQ, Zuora, Chargebee, Maxio and DealHub, with Nue differentiating through its unified quote-to-revenue architecture.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Replacing fragmented CPQ and billing stacks$q$, $q$Consolidate Salesforce CPQ, a separate billing tool and manual revenue recognition into one connected platform.$q$, $q$Mid-market and enterprise SaaS RevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Launching usage-based pricing models$q$, $q$Design, test and roll out new usage-based or hybrid pricing plans without lengthy engineering projects.$q$, $q$SaaS product and pricing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Accelerating sales quote turnaround$q$, $q$Let sales reps generate complex, multi-product quotes and proposals significantly faster than with legacy CPQ tools.$q$, $q$Enterprise sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$Custom$q$, $q$Contact sales$q$, $q$custom$q$, NULL, $q$["CPQ and quoting","Subscription and usage-based billing","Revenue intelligence dashboards","Native Salesforce integration","Implementation and onboarding support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nue is a quote-to-revenue platform for B2B SaaS companies, founded in 2019 (originally as Ruby.io) and headquartered in San Francisco. It unifies configure-price-quote (CPQ), subscription and usage-based billing, order management and revenue intelligence into a single platform, replacing the common approach of running separate CPQ, billing and revenue-recognition tools.$q$, $q$The company has raised around $35 million in total funding, including a $20 million Series A led by Inovia Capital in 2025, and has grown to roughly 120 employees as it scales its customer base of mid-market and enterprise SaaS companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nue's Price Builder lets revenue teams design and deploy complex pricing models and promotions quickly, while its quoting engine helps sales reps assemble multi-product proposals and send them out substantially faster than with legacy CPQ tools.$q$, $q$On the finance side, Nue supports usage-based, subscription and hybrid billing models along with revenue intelligence dashboards that give real-time visibility into ARR, renewals and expansion revenue, removing the need for manual reconciliation across disconnected billing and CRM systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ec4f000a-01b3-43af-b663-6371cea0d208', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nue does not publish public, self-serve pricing. As an enterprise quote-to-cash platform, pricing is quoted individually based on a company's revenue model, transaction volume, integrations needed and implementation scope.$q$, $q$Prospective customers typically request a live demo through Nue's website, after which the sales team scopes a custom package and implementation timeline, with fast-track onboarding programs available for teams needing to go live within a matter of weeks.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Economic nexus monitoring$q$, $q$Automatically tracks transaction volume and revenue against state-by-state economic nexus thresholds.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Automated tax registration$q$, $q$Initiates state tax registration automatically once a nexus threshold is crossed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Tax calculation API$q$, $q$Applies accurate sales tax at checkout through integrations with Stripe, Shopify, Amazon and NetSuite.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Filing and remittance with guarantee$q$, $q$Prepares and submits sales tax returns on time, with a guarantee to cover penalties and interest for Numeral's errors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Exemption certificate management$q$, $q$Collects, validates and stores customer sales tax exemption certificates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Virtual mailboxes$q$, $q$Receives and digitizes government tax correspondence on the business's behalf.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Global VAT support$q$, $q$Extends compliance coverage to more than 80 countries for internationally selling businesses.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Fully automates a historically manual and error-prone compliance process end to end$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Filing guarantee covers penalties and interest for errors caused by Numeral$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Per-transaction pricing with no long-term contract required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Integrates directly with common billing and e-commerce platforms like Stripe and Shopify$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Backed by significant recent funding ($57M total, including a 2025 Series B), suggesting strong ongoing investment in the product$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$No public, self-serve pricing, businesses must get a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$As a company founded in 2023, it has a shorter track record than legacy providers like Avalara$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Primarily optimized for e-commerce and SaaS billing stacks, may be less suited to businesses on niche platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Global VAT support, while offered, is a newer capability compared to the platform's core US sales tax focus$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Full automation requires accurate integration setup, mistakes in initial configuration could affect filings$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$What is Numeral used for?$q$, $q$Numeral is used by e-commerce and SaaS businesses to automate US sales tax compliance, including nexus monitoring, registration, tax calculation, filing and remittance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$How much does Numeral cost?$q$, $q$Numeral uses per-transaction pricing based on the number of tax registrations and filings needed, with no long-term contracts. Exact pricing requires a custom quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Who founded Numeral?$q$, $q$Numeral was founded in 2023 by Sam Ross and Matt DuVall, former engineers at Stripe and Notion, and is headquartered in San Francisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Does Numeral guarantee on-time tax filing?$q$, $q$Yes, Numeral guarantees that sales tax will be filed on time, or it will cover any resulting penalties and interest charges caused by its error.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$What platforms does Numeral integrate with?$q$, $q$Numeral integrates with billing and e-commerce platforms including Stripe, Shopify, Amazon and NetSuite, among others.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Does Numeral support international tax compliance?$q$, $q$Yes, in addition to US sales tax, Numeral offers global VAT compliance support across more than 80 countries.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$What are alternatives to Numeral?$q$, $q$Common alternatives include Avalara, TaxJar, Vertex and Anrok, with Numeral differentiating through its AI-driven, done-for-you approach and filing guarantee.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Multi-state nexus compliance$q$, $q$Automatically track and register for sales tax obligations as an e-commerce business crosses economic nexus thresholds in new states.$q$, $q$Growing e-commerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$SaaS sales tax automation$q$, $q$Handle the calculation, filing and remittance of sales tax on software subscriptions across jurisdictions with varying digital goods tax rules.$q$, $q$B2B and B2C SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Outsourced tax operations for finance teams$q$, $q$Replace manual spreadsheet tracking or a costly managed-services provider with an automated, guaranteed filing process.$q$, $q$Finance and accounting teams at scaling companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$Per-transaction (custom)$q$, $q$Contact sales$q$, $q$usage-based, no long-term contract$q$, NULL, $q$["Nexus monitoring and automated registration","Tax calculation API","Filing and remittance with penalty guarantee","Exemption certificate management","Virtual mailbox for tax correspondence"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Numeral is an AI-native sales tax compliance platform founded in 2023 by former Stripe and Notion engineers Sam Ross and Matt DuVall, and headquartered in San Francisco. The company went through Y Combinator and has since raised approximately $57 million in total funding, including a $35 million Series B led by Mayfield in 2025.$q$, $q$Numeral automates the full US sales tax lifecycle for e-commerce and SaaS businesses, from nexus monitoring and registration through tax calculation, filing and remittance, positioning itself as a done-for-you alternative to manual compliance processes or traditional tax software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Numeral's nexus monitoring engine tracks transaction volume and revenue against each state's economic nexus thresholds and automatically triggers registration once a business crosses a threshold, removing the need for finance teams to track this manually across dozens of jurisdictions.$q$, $q$Its tax calculation API integrates with platforms like Stripe, Shopify, Amazon and NetSuite to apply correct sales tax at checkout, while its filing and remittance service prepares and submits returns on the customer's behalf, backed by a guarantee to cover penalties and interest for any late filing caused by Numeral's error.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c9efa528-a016-40bf-b672-db270aa7c09d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Numeral prices per transaction based on the number of tax registrations and filings a business requires, rather than a flat monthly SaaS fee, and does not require long-term contracts.$q$, $q$Exact pricing depends on the number of states a business is registered in and its filing frequency, so prospective customers typically get a tailored quote after sharing their transaction volume and jurisdictional footprint.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Personalized meal planning$q$, $q$Build custom meal plans for clients using a library of 100-plus templates, recipes and infographics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Telehealth video consultations$q$, $q$Conduct remote client sessions directly within the platform with built-in secure video calling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Automated scheduling and reminders$q$, $q$Manage appointment booking, reminders and follow-ups without manual coordination.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Dietary and nutrient assessment$q$, $q$Analyze client dietary intake against nutritional targets using built-in assessment tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Client mobile app$q$, $q$Give clients a dedicated app to log meals, view meal plans and message their practitioner between sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Progress tracking$q$, $q$Visualize client progress over time with charts and reports shared between practitioner and client.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Invoicing and payments$q$, $q$Collect payments and manage billing for consultations directly within the platform.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Purpose-built specifically for nutrition professionals rather than adapted from generic EHR software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Combines meal planning, telehealth, scheduling and billing in a single subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Client-facing mobile app improves engagement and communication between sessions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Both pricing tiers include the full feature set, so practitioners aren't forced to pay more just to unlock features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Well-funded and established company (founded 2015, $19.8M raised) with a large existing user base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$No permanently free plan, only a 14-day trial before payment is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Pricing is tied to client volume, so costs rise as a practice grows past 10 clients on the lower tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Monthly billing is notably more expensive than annual billing, which requires an upfront commitment for the best rate$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Feature depth in areas like insurance billing may be more limited than region-specific competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$As a practice-specific tool, it lacks broader general-purpose EHR capabilities some multi-specialty clinics may need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$What is Nutrium used for?$q$, $q$Nutrium is used by nutritionists and dietitians to manage their practice, including meal planning, telehealth consultations, appointment scheduling, dietary assessment and client billing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Is Nutrium free?$q$, $q$Nutrium does not offer a permanently free plan, but it does include a 14-day free trial on all plans before payment is required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$How much does Nutrium cost?$q$, $q$Nutrium's lower-volume plan (up to 10 clients/month) starts around $15/month billed annually, and the Unlimited Clients plan starts around $25/month billed annually; monthly billing is priced higher.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Does Nutrium support telehealth?$q$, $q$Yes, Nutrium includes built-in secure telehealth video consultations and in-app chat for remote client sessions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Who founded Nutrium?$q$, $q$Nutrium was founded in 2015 in Braga, Portugal by Pedro Carneiro, Diogo Alves and Andre Santos.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Does Nutrium have a client-facing app?$q$, $q$Yes, Nutrium offers a mobile app for clients to log meals, view their meal plans and message their practitioner between appointments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$What are alternatives to Nutrium?$q$, $q$Common alternatives include NutriAdmin, Healthie and Cronometer Professional, with Nutrium differentiating through its all-in-one combination of meal planning, telehealth and practice management.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Solo dietitian private practice$q$, $q$Run an entire nutrition practice, from scheduling and consultations to meal planning and billing, in one platform.$q$, $q$Independent dietitians and nutritionists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Remote nutrition coaching$q$, $q$Deliver telehealth consultations and ongoing meal plan support to clients who can't attend in person.$q$, $q$Nutrition coaches serving remote clients$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Corporate and workplace nutrition programs$q$, $q$Support in-house nutrition teams delivering employee wellness and nutrition benefits at scale.$q$, $q$Corporate wellness and HR benefits teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$10 Clients/Month$q$, $q$$15/month$q$, $q$billed annually ($25/month billed monthly)$q$, NULL, $q$["Up to 10 clients per month","Personalized meal plans","Telehealth and secure chat","Appointment scheduling","Invoicing and payments","14-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$Unlimited Clients$q$, $q$$25/month$q$, $q$billed annually ($39/month billed monthly)$q$, NULL, $q$["Unlimited clients","Personalized meal plans","Telehealth and secure chat","Appointment scheduling","Invoicing and payments","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nutrium is cloud-based practice management and EHR software purpose-built for nutritionists and dietitians, founded in 2015 in Braga, Portugal by Pedro Carneiro, Diogo Alves and Andre Santos. The company has raised approximately $19.8 million in funding and grown into one of the largest dedicated software providers serving the global nutrition and dietetics profession.$q$, $q$Rather than adapting generic scheduling or EHR software to nutrition workflows, Nutrium was designed from the ground up around the specific needs of a nutrition practice: meal planning, dietary analysis, client communication and the business operations that come with running a private practice.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nutrium lets practitioners build personalized meal plans using a library of over 100 ready-to-use templates, recipes and client-facing infographics, and includes dietary assessment tools for analyzing nutrient intake against targets. Appointments can be scheduled automatically with reminders, and sessions can be conducted remotely through built-in secure chat and telehealth video.$q$, $q$A companion client mobile app lets patients log meals, message their practitioner and review their meal plans between appointments, while built-in invoicing and payment collection let practitioners manage billing without a separate tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c10d8d2-81ae-4c01-b041-bf40e0c15cf4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nutrium prices by client volume rather than by feature access, since both plans include the platform's full functionality. The lower-volume plan, capped at 10 clients per month, starts around $15/month billed annually (or $25/month billed monthly).$q$, $q$The Unlimited Clients plan starts around $25/month billed annually (or $39/month billed monthly) for practitioners with larger caseloads. There is no permanently free tier, but both plans include a 14-day free trial.$q$]::text[], 2);
