-- Enrichment marathon batch: Novu, nTask, ntfy, Nuclei, Nuclino, Nue, Numeral, Nutrium

-- ── Novu ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Novu is an open-source notification infrastructure platform that lets developers trigger multi-channel notifications (email, SMS, push, chat and in-app) from a single API call and manage them with a visual workflow editor.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $30/month)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Novu Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Novu review 2026: open-source notification infrastructure for developers. See features, workflow-run pricing, integrations, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Novu is an open-source notification infrastructure platform for developers, founded in 2021 in Tel Aviv, Israel (originally launched as Notifire) by a small founding team that had repeatedly built and rebuilt in-house notification systems at previous companies. The company raised a $6.6 million seed round led by Crane Venture Partners, with participation from Eniac, MXV Capital, Entree Capital and angel investors including Ariel Maislos, to build a unified layer that lets engineering teams manage multi-channel messaging (email, SMS, push, chat and in-app inbox) through one API instead of stitching together separate provider SDKs for Twilio, SendGrid, Firebase, Slack and others. Its core open-source repository has become one of the most-starred notification projects on GitHub, and the hosted Novu Cloud sits on top of the same open-source workflow engine, so teams can self-host for free or pay for managed infrastructure. The product centers on a drag-and-drop workflow builder where developers define trigger conditions, channel fallbacks, digesting and batching logic, delay steps and in-app inbox rendering, then call a single trigger event from application code; Novu resolves which channels and providers to use per subscriber based on their preferences. It ships an embeddable Inbox component (React, Angular, Vue, and a headless API) for in-app notification centers, more than 55 provider integrations across email, SMS, push and chat, subscriber preference management, and multi-environment support for staging versus production workflows. Pricing is usage-based on workflow runs (one run equals one trigger event that can fan out to multiple channels): a Free tier includes 10,000 monthly workflow runs, up to 20 workflows, 2 environments and 3 team members; Pro starts at $30/month for 30,000+ runs, 7-day activity retention and no Novu branding; Team starts at $250/month for 250,000+ runs, up to 10 environments, unlimited members and role-based access control; Enterprise is custom-priced for 10 million-plus runs with HIPAA BAA, SSO, SCIM, private support and self-hosting options. Novu's target audience is product and platform engineering teams -- at startups through mid-market SaaS companies -- who need reliable, auditable notification delivery without building and maintaining bespoke messaging infrastructure. Its primary competitors include Courier, Knock, Suprsend and in-house solutions built directly on provider APIs like Twilio and SendGrid; Novu differentiates through its open-source core, generous self-hosting option, and developer-first workflow-as-code approach.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '555aaf18-6846-4042-ba95-cc4fd3189aec';

