-- ── ntfy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ntfy is a simple, open-source HTTP-based pub-sub push notification service that lets developers and self-hosters send notifications to phones, desktops and scripts using basic PUT or POST requests.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted or public server); hosted plans from $5/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ntfy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$ntfy review 2026: open-source push notifications via simple PUT/POST requests. Self-host free or use the hosted service. See features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ntfy (pronounced 'notify') is a free and open-source, HTTP-based publish-subscribe notification service created by developer Philipp Heckel (GitHub handle binwiederhier) that lets anyone send push notifications to a phone, desktop or script with a single PUT or POST request, no account, SDK or app registration required. Topics are created on the fly simply by publishing or subscribing to a topic name, which acts as a lightweight, semi-private channel; subscribers receive messages instantly on iOS, Android, desktop browsers and via the command line. The project is licensed under Apache 2.0 and GPLv2, has grown to over 30,000 GitHub stars and 300-plus contributors, and ships frequent releases, making it a cornerstone of the self-hosting and homelab community as well as a popular choice for developer automation, CI/CD alerts, monitoring notifications and IoT/home-automation triggers. ntfy integrates natively with tools like GitHub Actions, Home Assistant, Sonarr, Radarr, Uptime Kuma and dozens of other self-hosted and DevOps tools, and supports rich notification features including priorities, action buttons, tags, emoji, file attachments and delivery scheduling. Because it is fully open source, anyone can self-host their own ntfy server at zero cost, retaining complete control over data and message topics. For users who do not want to run their own server, the project also operates a free public server at ntfy.sh (usable without signup, though topics are only semi-private since anyone who knows or guesses the topic name can subscribe) as well as a paid hosted tier that funds ongoing development: the Supporter plan is about $5-6/month with higher daily message limits, reserved (fully private) topics and larger attachment sizes; Pro is about $10-12/month with substantially higher throughput; and Business is about $20-25/month for teams needing the highest limits, with larger dedicated deployments available on request. ntfy's target users are developers, DevOps engineers, and self-hosting hobbyists who want simple, scriptable push notifications without the overhead of building a full notification pipeline or paying for a heavyweight commercial platform like Pushover or PagerDuty. Its main differentiator versus commercial alternatives like Pushover, Pushbullet or OneSignal is that the entire stack is open source and self-hostable, giving privacy-conscious and cost-conscious users a genuine free option rather than a limited trial.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '65e976a6-18cc-449b-b109-b26bbd870c7c';

