-- ── Nuclei ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nuclei is a fast, open-source, template-based vulnerability scanner from ProjectDiscovery that uses a YAML DSL to detect security issues across web applications, APIs, networks, DNS and cloud configurations.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); ProjectDiscovery Cloud Platform pricing is custom$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nuclei Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nuclei review 2026: ProjectDiscovery's open-source, template-based vulnerability scanner. See features, YAML DSL scanning, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nuclei is an open-source, template-based vulnerability scanner built by ProjectDiscovery, a cybersecurity company founded in 2019 by Sandeep Singh, Rishiraj Sharma, Marco Rivoli and Nizamul Rana and headquartered in San Francisco, California. Rather than relying on hardcoded, general-purpose scanning logic, Nuclei runs against a target using thousands of community-authored and officially maintained YAML-based templates, each expressing a specific vulnerability check, misconfiguration signature or exposure pattern, spanning web application vulnerabilities, exposed panels and default credentials, DNS and network issues, API weaknesses, cloud misconfigurations, and CVEs disclosed for popular software. Because checks are defined declaratively in a simple domain-specific language rather than compiled code, the security community can write, share and update templates rapidly, which is why Nuclei's public template repository grows continuously to cover newly disclosed CVEs, often within hours of public disclosure. Nuclei is written in Go for speed and low resource usage, supports massively parallel scanning across large target lists, and integrates cleanly into CI/CD pipelines, bug bounty workflows and continuous attack-surface monitoring programs. It sees more than 50 million scans per month from security researchers, penetration testers and engineering teams in over 100 countries, and is one of the most widely adopted open-source vulnerability scanners in the security community, alongside tools like Nmap, OpenVAS and Burp Suite. Nuclei itself is completely free and open source under an MIT-style license with no feature paywall; ProjectDiscovery instead monetizes through a separate commercial product, the ProjectDiscovery Cloud Platform, which layers continuous attack-surface management, hosted scanning infrastructure, team collaboration and reporting on top of the open-source Nuclei engine at custom, sales-quoted pricing. ProjectDiscovery has raised a total of roughly $25 million, including a $25 million Series A round in 2023 led by CRV with participation from Point72 Ventures, SignalFire, Accel and Lightspeed, among others. Nuclei's target users are penetration testers, red teams, bug bounty hunters, application security engineers and DevSecOps teams who need fast, automatable, continuously updated vulnerability detection that plugs directly into existing security tooling and CI/CD workflows, rather than a closed-source commercial scanner with a fixed vulnerability database.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '753fe4a9-11ba-48d6-b0b2-d0fabb12b2bb';

