-- ── Nuclino ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nuclino is a fast, real-time team wiki and knowledge base that lets teams create, organize and collaboratively edit documents, notes and boards in a single lightweight workspace.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $6/user/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Grunwald, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nuclino Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nuclino review 2026: the fast, real-time team wiki for docs and knowledge bases. Compare features, pricing plans and top Nuclino alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nuclino is a real-time collaborative team wiki and knowledge base platform founded in 2015 near Munich, Germany by co-founders Bjorn Michelsen (CEO), Jonathan Kienzle (CTO) and Veronika Fischer (COO), and now headquartered in Grunwald, Germany. The company is notable for being fully bootstrapped and profitable, having raised no external venture funding while growing to over $3 million in annual recurring revenue with a lean team of roughly 20 people, and reporting around $598,000 in 2024 revenue on a platform serving over 12,000 customers. Nuclino's core pitch is speed and simplicity: it is marketed as 'your team's collective brain,' a lightweight internal wiki that loads instantly, avoids the feature bloat of larger tools like Notion or Confluence, and lets teams organize documentation, meeting notes, product specs and onboarding material in nested, interlinked items. Content is organized into workspaces containing collections of items that can be viewed as a list, board (Kanban-style), grid or graph view showing how documents link to one another, and editing happens in real time with Google Docs-style multiplayer cursors. Nuclino supports rich text editing, embedded files, code blocks and diagrams, deep linking between items to build a wiki-style knowledge graph, and integrations with tools like Slack, Figma and Google Drive for embedding external content directly into pages. Pricing follows a freemium SaaS model: the Free plan supports up to 50 items and 2 GB of total storage, suitable for individuals or very small teams evaluating the product; the Starter plan is priced at roughly $6 per user per month billed annually (around $8/month billed monthly) and unlocks unlimited items and boards along with more integrations; the Business plan is around $10 per user per month and adds AI-powered features, advanced permissions, audit logs and enterprise-grade security controls; and an Enterprise tier is available at custom pricing for larger organizations with specific compliance or deployment needs. Nuclino's target audience is small to mid-sized teams -- particularly startups, agencies and remote-first companies -- that want a fast, distraction-free internal wiki without the complexity, cost or steep learning curve of Notion, Confluence or Coda. Its primary competitors include Notion, Confluence, Slite, Coda and Guru, with Nuclino differentiating itself on raw speed, minimalism and its unique graph view of interlinked documents.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '31891521-7412-481e-8809-b74fa059bcf3';

