-- ── Nue ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nue is an omnichannel quote-to-revenue platform for B2B SaaS companies, unifying CPQ (configure-price-quote), subscription billing, revenue recognition and usage-based pricing in one system.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nue Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nue review 2026: omnichannel quote-to-revenue platform for B2B SaaS. See CPQ, billing and revenue features, pricing model and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nue is a quote-to-revenue platform for B2B SaaS companies, originally founded in 2019 under the name Ruby.io before rebranding to Nue, and headquartered in San Francisco, California. The company has raised approximately $35 million in total funding across three rounds, including a $20 million Series A announced in early 2025 led by Inovia Capital with participation from Information Venture Partners, Bluefish Capital, NextWorld Capital, NJP Ventures and Operator Stack Fund, and has grown from roughly 41 employees in 2023 to around 120 employees by 2026, with reported annual revenue near $10 million. Nue positions itself as a modern, unified alternative to stitching together separate CPQ, billing and revenue-recognition point solutions (commonly Salesforce CPQ, Zuora and a separate revenue recognition tool), instead delivering configure-price-quote, subscription and usage-based billing, order management, and revenue intelligence on a single platform built natively on Salesforce and designed for the complexity of modern SaaS pricing models like seat-based, usage-based and hybrid pricing. Core capabilities include a Price Builder for deploying and testing pricing and promotions quickly, a quote and order management module that lets sales reps build complex, multi-product quotes and get customer proposals out significantly faster than legacy CPQ tools, flexible billing that supports usage-based, subscription and hybrid revenue models, and revenue intelligence dashboards that give finance teams real-time visibility into ARR, expansion and renewal metrics without manual reconciliation across systems. Nue integrates with e-signature and contract lifecycle tools including DocuSign, Ironclad, PandaDoc and Conga, and offers implementation programs, including a Quick Start track that aims to get customers from kickoff to production in as little as four to six weeks. Nue does not publish self-serve pricing; prospective customers request a live demo and receive a custom quote based on their revenue model, deal volume and existing tech stack, which is typical for enterprise-grade quote-to-cash software. Nue's target audience is mid-market and enterprise B2B SaaS companies -- particularly those with complex, evolving pricing models -- whose revenue operations, sales and finance teams have outgrown spreadsheets or a legacy CPQ tool like Salesforce CPQ. Its main competitors include Salesforce CPQ, Zuora, Chargebee, Maxio (formerly SaaSOptics/Chargify) and DealHub, with Nue differentiating through its unified quote-to-revenue architecture rather than requiring separate best-of-breed tools stitched together via integrations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ec4f000a-01b3-43af-b663-6371cea0d208';

