-- ── Nutrium ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nutrium is cloud-based practice management and EHR software for nutritionists and dietitians, combining meal planning, telehealth, scheduling and client management in one platform.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$15/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Braga, Portugal$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nutrium Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nutrium review 2026: cloud-based practice management software for dietitians. See meal planning, telehealth and scheduling features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nutrium is cloud-based practice management and electronic health record (EHR) software built specifically for nutritionists and dietitians, founded in 2015 in Braga, Portugal by Pedro Carneiro, Diogo Alves and Andre Santos. The company has raised roughly $19.8 million across four funding rounds and has grown to a team estimated between 90 and 190 employees depending on the source, positioning it as one of the largest dedicated software vendors serving the nutrition and dietetics profession globally, marketed as 'the world's number one nutrition software.' Nutrium's platform consolidates the tools a nutrition practice needs into one system: personalized meal plan creation with access to a library of 100-plus ready-to-use templates, recipes and client-facing infographics; automated appointment scheduling with reminders and follow-ups; secure in-app chat and telehealth video consultations for remote client sessions; dietary and nutrient assessment tools that let practitioners analyze a client's intake against nutritional targets; visual progress tracking so clients and practitioners can see trends over time; and built-in invoicing and payment collection so practitioners can run the business side of their practice without a separate billing tool. The platform also offers a client-facing mobile app that lets patients log meals, message their practitioner and view their meal plans between sessions, which is a key differentiator versus generic EHR or scheduling software not built for the nutrition workflow. Pricing is structured around client volume rather than feature tiers: both of Nutrium's plans include the full feature set, so a solo practitioner or dietitian starting out can choose the lower-priced plan capped at 10 clients per month (roughly $15/month billed annually, or $25/month billed monthly) and upgrade to the Unlimited Clients plan (roughly $25/month billed annually, or $39/month billed monthly) as their caseload grows, with all plans including a 14-day free trial and no permanently free tier. Nutrium's target audience is independent dietitians, nutritionists and small nutrition clinics, as well as larger healthcare organizations and corporate wellness programs that license Nutrium's software for their in-house nutrition teams (the company has separately expanded into workplace nutrition and employee benefits offerings). Its primary competitors include NutriAdmin, Healthie, Nutrium's category peers like Cronometer Professional and general practice-management tools adapted for nutrition use, with Nutrium differentiating through its purpose-built combination of meal planning, telehealth and practice management in a single platform designed specifically around the day-to-day workflow of a nutrition professional.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3c10d8d2-81ae-4c01-b041-bf40e0c15cf4';

